const express = require('express');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Twilio configuration
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// In-memory storage for SMS codes with session IDs
const smsCodes = {};

// Generate a random 6-digit code
function generateCode() {
    return Math.floor(100000 + Math.random() * 900000).toString();
}

// Send SMS with the generated code
async function sendSMS(phoneNumber, code) {
    try {
        await client.messages.create({
            body: `Your verification code is ${code}`,
            from: 'your_twilio_phone_number',
            to: phoneNumber
        });
        console.log(`Code sent to ${phoneNumber}: ${code}`);
    } catch (error) {
        console.error('Error sending SMS:', error);
    }
}

// Route to initiate MFA
app.post('/initiate-mfa', async (req, res) => {
    const { phoneNumber } = req.body;
    if (!phoneNumber) {
        return res.status(400).json({ message: 'Phone number is required' });
    }

    const code = generateCode();
    smsCodes[phoneNumber] = { code, timestamp: Date.now() };

    await sendSMS(phoneNumber, code);

    res.json({ message: 'Verification code sent' });
});

// Route to verify MFA
app.post('/verify-mfa', (req, res) => {
    const { phoneNumber, code } = req.body;
    if (!phoneNumber || !code) {
        return res.status(400).json({ message: 'Phone number and code are required' });
    }

    if (smsCodes[phoneNumber] && smsCodes[phoneNumber].code === code) {
        const currentTime = Date.now();
        const timeDifference = currentTime - smsCodes[phoneNumber].timestamp;
        if (timeDifference < 60000) { // Code valid for 1 minute
            delete smsCodes[phoneNumber];
            res.json({ message: 'Verification successful' });
        } else {
            res.status(403).json({ message: 'Code expired' });
        }
    } else {
        res.status(403).json({ message: 'Invalid code' });
    }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
});